Greedy insertion with penalty-augmented regret-based scoring considering both distance increase and time window violation penalties across all feasible positions and assigns, with fallback to new assign seeded at earliest feasible station.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const alpha = 1.0
	const beta = 50.0
	const gamma = 10.0
	type candidate struct {
		assignIdx int
		score     float64
		ok        bool
	}
	for shipID := 0; shipID < len(oris); shipID++ {
		id := total_ship + shipID
		bestScore := 1e100
		bestIdx := -1
		savedCosts := make([]float64, dispatch.AssignsLen)
		for i := 0; i < dispatch.AssignsLen; i++ {
			savedCosts[i] = dispatch.Assigns[i].Cost
		}
		for i := 0; i < dispatch.AssignsLen; i++ {
			assign := &dispatch.Assigns[i]
			ok := assign.AddShip(id, oris[shipID], dess[shipID])
			if !ok {
				continue
			}
			assign.GenRoute()
			newCost := assign.Cost
			delta := newCost - savedCosts[i]
			penalty := 0.0
			if newCost < 0 || delta < 0 {
				penalty += gamma
			}
			regret := 0.0
			if delta > 0 {
				regret = delta * alpha
			}
			distInc := 0.0
			curLen := assign.StationsLen
			if curLen >= 3 {
				st1 := assign.Stations[curLen-3]
				st2 := assign.Stations[curLen-2]
				st3 := assign.Stations[curLen-1]
				distInc = cal_dis(st1, st2) + cal_dis(st2, st3)
			}
			score := regret + beta*penalty + distInc
			if score < bestScore {
				bestScore = score
				bestIdx = i
			}
			assign.RemoveShip(id)
			assign.Cost = savedCosts[i]
			assign.GenRoute()
		}
		commitIdx := -1
		if bestIdx != -1 {
			commitIdx = bestIdx
		} else if dispatch.AssignsLen < MAXASSIGNS {
			commitIdx = dispatch.AssignsLen
		} else {
			for i := 0; i < dispatch.AssignsLen; i++ {
				assign := &dispatch.Assigns[i]
				if assign.AddShip(id, oris[shipID], dess[shipID]) {
					assign.GenRoute()
					if assign.Cost >= 0 {
						commitIdx = i
						break
					}
					assign.RemoveShip(id)
					assign.Cost = savedCosts[i]
					assign.GenRoute()
				}
			}
			if commitIdx == -1 && dispatch.AssignsLen < MAXASSIGNS {
				commitIdx = dispatch.AssignsLen
			}
		}
		if commitIdx == -1 {
			continue
		}
		if commitIdx >= dispatch.AssignsLen {
			dispatch.AssignsLen = commitIdx + 1
		}
		dispatch.Assigns[commitIdx].AddShip(id, oris[shipID], dess[shipID])
		dispatch.Assigns[commitIdx].GenRoute()
	}
	dispatch.RenewnTotalCost()
	return dispatch

